        <a
          className="App-link"
          href="https://reactjs.org"
          target="_blank"
          rel="noopener noreferrer"
        >
          Link
        </a> */}
        <div>
          <canvas id="canvas" />
        </div>
      </header>
    </div>
  );
}

export default App;
